#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 音乐制作 / 混音.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="音乐制作 / 混音"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 风格语境 / camp 定位
  9.2 Pipeline 阶段 + 当前瓶颈定位
  9.3 工具栈现状 + 近期 AI 落地点核查
  9.4 响度 / 交付目标核查
  9.5 流派立场冲突识别
  9.6 reference / 外部校准现状核查

背后的心智模型:
  • 服务歌优先于服务技术 (serve the song): 技术、音色、个人风格全都服从于"这首歌要表达什么"——好不好的最终裁判是情绪与歌本身，不是参数表（"if it sounds good, it is good"）。
  • 减法优先 / 每个处理都要能说出理由 (less but knowing why): 默认不处理；做得太多而非太少是这一行最常见的病——加任何东西（轨/EQ/压缩/响度）之前，先确认能不能减、不加，且每一次处理都要能讲出"我为什么这么做"。
  • 所有听感判断都要外部校准（耳朵、房间、AI 营销都会骗你）: 人耳会疲劳、房间会撒谎、"更响/更不一样"会被误判成"更好"、AI 营销会兜售安慰剂——所以所有听感判断都要靠外部锚点校准：响度匹配后的 reference track、校准监听、mono/多系统/低

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "风格语境 / camp 定位"
  "Pipeline 阶段 + 当前瓶颈定位"
  "工具栈现状 + 近期 AI 落地点核查"
  "响度 / 交付目标核查"
  "流派立场冲突识别"
  "reference / 外部校准现状核查"
)
declare -a DIM_QUESTIONS=(
  "用户做的是哪个 genre + 哪个流派立场（流行/R&B/hip-hop-trap/电子/摇滚/金属/独立；invisible vs character、auteur vs serve-the-song）——决定整套默认值（DAW、压缩哲学、响度容忍度、是否追签名音色）。"
  "用户处在 arrangement/tracking/editing/mixing/mastering/delivery 哪一环，当前最痛的瓶颈是什么（频段/动态/空间/响度/交付格式）——决定该回上游还是在本环解决。"
  "用户现有 DAW/插件/硬件 + 是否在用（或该不该用）AI EQ/AI 母带/stem 分离/mix assistant，以及该工具近 12 个月有无新版本/新 ML 模块改变行为。"
  "目标渠道与规格——平台 LUFS target（Spotify -14 / Apple -16 / Deezer -15）、true-peak 余量、是否需 DDP（压盘）/ stems / Dolby Atmos ADM BWF；以及 BS.1770/R128 是否有新修订。"
  "用户的诉求或现有做法是否踩在某条流派轴的争议点上（ITB vs analog mojo、invisible vs character、ears vs metrics、loudness vs dynamics、bedroom vs 高端棚、AI 是否毁 craft）——避免把一派偏见当唯一答案。"
  "用户的监听/房间是否处理校准、有没有 reference track 习惯、A/B 时是否响度匹配、混音是否做 mono/多系统/低音量复核——这是代偿 tacit listening ceiling 的核心抓手。"
)
declare -a DIM_SOURCES=(
  "用户自述的参考艺人/reference 曲；对应 camp 的 figure 长访谈（SOS \"Secrets of the Mix Engineers\" / Tape Op / MWTM masterclass）；Track 01 六 camp 分组。"
  "用户描述的症状（mud/harsh/平/糊/被打回）；Track 03 七 workflow 的失败模式与入门-资深差异；Track 02 决策树 Branch 1-4。"
  "Track 02 三层工具栈 + 新兴层 last_checked 日期；FabFilter/iZotope/sonible release notes（vendor docs）；MusicTech/SOS 评测；Dan Worrall null-test 视频（验证\"是否真更好\"）。"
  "iZotope mastering-for-streaming 多平台 target 表（T06-S017）；平台官方文档（Spotify for Artists）；ITU-R BS.1770 / EBU R128 官方（T06-S001/S002）；Track 03 delivery workflow。"
  "Track 04 canon \"still-debated\" 列表；Track 06 厂商话术拒绝 top 5 + mojo 簇 disputed 标注；Track 01 figures 间分歧（Scheps vs CLA 等）。"
  "用户自述的监听设备/房间；Track 02 监听条目（校准+声学处理优先）；Track 03 各 workflow 的\"add: 外部校准\"差异点；Track 06 reference/A-B/null test/mono compatibility 定义。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "1-2 句——\"用户在 {camp}，默认走 {流派立场} 的处理哲学与工具默认值，避开 {对立 camp} 的不适配预设\"。"
  "1-2 句——\"瓶颈在 {阶段/频段}，建议 {回上游 X / 本环用 Y 工具}，对应 reference A/B 校准点是 {Z}\"。"
  "1-2 句——\"工具栈 {现状}，AI 工具 {X} 当起点用、需 null/A-B；近期变化 {版本/ML 模块} 影响 {behavior}（last_checked: {date}, Decay risk: {level}）\"。"
  "1-2 句——\"目标渠道 {X}，母带 target ≈ {LUFS}、true-peak ≤ -1 dBTP（官方/业内共识 T03-S004）、{需/不需} DDP/stems/Atmos；标准最近修订 {BS.1770-5 / R128 v5.0, 2023-11}\"。"
  "1-2 句——\"该诉求落在 {轴} 上，A 派主张 {…}、B 派主张 {…}；并列呈现，建议按用户 camp/目标选边并说明代价，不抹平\"。"
  "1-2 句——\"校准现状 {房间/监听/reference 习惯}，缺口在 {未处理房间/未响度匹配 A/B/未查 mono}，优先补 {声学处理 / gain-match reference / mono 复核}\"。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
